// Parse the extractor's JSON, validate the groundedness contract, and count.
// Any requirement without a verbatim quote is dropped and logged - this is the
// quote-or-it-doesn't-exist rule enforced in code rather than left to the model.

const raw = $input.first().json;
let text = raw.text ?? raw.output ?? raw.response ?? '';
if (typeof text === 'object') text = JSON.stringify(text);

// tolerate ```json fences
text = String(text).replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

let ex;
try {
  ex = JSON.parse(text);
} catch (e) {
  throw new Error('Extractor did not return valid JSON. Raw output: ' + text.slice(0, 500));
}

const arr = (k) => Array.isArray(ex[k]) ? ex[k] : [];
const hasQuote = (o) => typeof o.quote === 'string' && o.quote.trim().length > 0;

// Groundedness gate: drop unsupported items, keep them for the trace.
const dropped = [];
const stated = arr('stated_requirements').filter(r => {
  if (!hasQuote(r)) { dropped.push({ where: 'stated_requirements', item: r }); return false; }
  return true;
});
const personas = arr('personas').filter(p => {
  if (!hasQuote(p)) { dropped.push({ where: 'personas', item: p }); return false; }
  return true;
});

const extraction = {
  ...ex,
  stated_requirements: stated,
  personas: personas,
};

return [{
  json: {
    // Inside the loop, read the CURRENT batch item. $('Combine All Sources') ran
    // once with every file, so .first() there would pin everything to file #1.
    input_text: $('Combine All Sources').first().json.input_text,
    test_id: $('Combine All Sources').first().json.test_id,
    extraction,
    gaps: {
      ambiguous_items: arr('ambiguous_items'),
      contradictions: arr('contradictions'),
      not_discussed: arr('not_discussed'),
      missing_information: arr('missing_information'),
      stakeholders: arr('stakeholders'),
    },
    stated_count: stated.length,
    ambiguous_count: arr('ambiguous_items').length,
    contradiction_count: arr('contradictions').length,
    input_assessment: ex.input_assessment ?? 'UNKNOWN',
    unsupported_items_dropped: dropped.length,
    dropped_items: dropped,
  }
}];

// Reach back to the source nodes for identity and metrics rather than relying on
// them surviving the trip through the LLM chain nodes - chainLlm returns only
// {text}, so anything not explicitly re-attached is dropped.
// Current loop item, not the pre-loop batch — otherwise every file is labelled #1.
const src  = $('Combine All Sources').first().json;
const meta = $('Parse + Validate Extraction').first().json;

const items = $input.all().map(i => i.json);
const pick = (k) => {
  for (const i of items) {
    const v = i[k];
    if (typeof v === 'string' && v.trim()) return v;
  }
  return '';
};

// Filesystem-safe. A fallback containing '/' would be read by n8n as a path
// separator and silently split the filename.
const testId = String(src.test_id ?? 'unknown').replace(/[^A-Za-z0-9._-]/g, '_');

return [{
  json: {
    test_id: testId,
    source_file: src.source_file ?? testId,
    input_assessment: meta.input_assessment ?? 'UNKNOWN',
    stated_count: meta.stated_count ?? 0,
    ambiguous_count: meta.ambiguous_count ?? 0,
    contradiction_count: meta.contradiction_count ?? 0,
    unsupported_items_dropped: meta.unsupported_items_dropped ?? 0,
    halted_at_sufficiency_gate: items.some(i => i.halted_at_sufficiency_gate === true),
    prd_markdown: pick('prd_markdown'),
    stories_markdown: pick('stories_markdown'),
    gap_markdown: pick('gap_markdown'),
  }
}];

// Chat is the PRIMARY input: it defines the scope of the PRD. Supporting
// documents in Drive may only ADD DETAIL to what the chat raises — they cannot
// introduce requirements of their own. With no chat requirements there is no
// scope, so the run halts rather than building a PRD from documents alone.
const raw = String($input.first().json.chatInput ?? '').trim();
const lower = raw.toLowerCase();

// Bare utility commands are not requirements.
const isCommand = /^(list|ls|what files|show files|all|go|run|ingest)$/.test(lower);
const has_requirements = raw.length > 0 && !isCommand;

// Optional "T1: ..." prefix tags the run in traces without changing behaviour.
const m = raw.match(/^\s*(T\d{1,2})\s*[:.\-]\s*([\s\S]+)$/i);

return [{ json: {
  has_requirements,
  list_only: /^(list|ls|what files|show files)$/.test(lower),
  primary_text: has_requirements ? (m ? m[2].trim() : raw) : '',
  test_id: (m ? m[1].toUpperCase() : (has_requirements ? 'chat' : 'none')),
  sessionId: $input.first().json.sessionId ?? null,
} }];

// Keep only readable text files as SUPPORTING documents. No filename filtering:
// under the primary/supporting design every document in the folder is available
// as detail for the chat's requirements — the chat, not a filter, sets scope.
const TEXTY = /^(text\/plain|text\/markdown|application\/vnd\.google-apps\.document)$/;
const files = $input.all().map(i => i.json).filter(f => TEXTY.test(String(f.mimeType || '')));
return files.map(f => ({ json: f }));

// Build ONE document with the chat request as PRIMARY INPUT and each Drive file
// as a SUPPORTING DOCUMENT. The extractor scopes the PRD to the PRIMARY block and
// uses SUPPORTING blocks only to add detail to what the chat raised.
const cmd = $('Read Chat Command').first().json;
const primary = String(cmd.primary_text || '').trim();

// Supporting docs (may be zero). $input carries the Binary-to-Text output.
const meta = (() => { try { return $('Keep Supporting Docs').all(); } catch (e) { return []; } })();
const docs = [];
$input.all().forEach((item, i) => {
  const j = item.json ?? {};
  const name = meta[i]?.json?.name ?? `document-${i + 1}`;
  const text = String(j.data ?? j.text ?? j.content ?? '').trim();
  if (text) docs.push({ name, text });
});

const blocks = [`=== PRIMARY INPUT (chat request — defines PRD scope) ===\n${primary}`];
docs.forEach(d => blocks.push(`=== SUPPORTING DOCUMENT: ${d.name} (detail only, cannot add scope) ===\n${d.text}`));

return [{ json: {
  test_id: cmd.test_id || 'chat',
  source_file: ['chat request', ...docs.map(d => d.name)].join(', '),
  source_count: 1 + docs.length,
  source_names: ['chat request', ...docs.map(d => d.name)],
  supporting_count: docs.length,
  input_text: blocks.join('\n\n'),
}}];

// One PRD, in three sections.
const passthru = $input.all().map(i => i.json).find(j => j && j.output && j.files_ingested === 0);
if (passthru) return [{ json: passthru }];

const r = $input.first().json;
const src = $('Combine All Sources').first().json;

// Push agent headings down one level so the three section headings stay outermost.
const demote = (md) => String(md || '').replace(/^(#{1,5}) /gm, '$1# ');
const none = '_Not generated — the sources did not contain enough stated requirements._';

const sources = (src.source_names || []).map(n => `\`${n}\``).join(' · ') || '_none_';

const header = r.halted_at_sufficiency_gate
  ? '> **No PRD generated.** No stated requirements were found across the sources, so the PRD Generator was never invoked.'
  : `> **${r.stated_count}** stated requirement(s) · **${r.ambiguous_count}** ambiguous · ` +
    `**${r.contradiction_count}** contradiction(s)` +
    (r.unsupported_items_dropped ? ` · **${r.unsupported_items_dropped}** unsupported dropped` : '');

const output = [
  '# PRD Genie',
  '',
  `Synthesised from **${src.source_count || 0}** source(s): ${sources}`,
  '',
  header,
  '', '---', '',
  '# 1. Product Requirements Document', '',
  r.halted_at_sufficiency_gate ? none : demote(r.prd_markdown || none),
  '', '---', '',
  '# 2. Epics and User Stories', '',
  r.halted_at_sufficiency_gate ? none : demote(r.stories_markdown || none),
  '', '---', '',
  '# 3. Clarification Questions', '',
  demote(r.gap_markdown || none),
].join('\n');

return [{ json: { output, sources_combined: src.source_count || 0,
                  halted: !!r.halted_at_sufficiency_gate } }];

// No requirements in the chat -> no scope -> no PRD (by design).
const j = $input.first().json;
if (j.list_only) {
  const files = (() => { try { return $('Keep Supporting Docs').all().map(i=>i.json.name); } catch(e){ return []; } })();
  const list = files.length ? files.map(f=>`- \`${f}\``).join('\n') : '_No supporting documents found._';
  return [{ json: { output: ['# Supporting documents in Drive','',list,'','Describe your requirements in the chat and I will build a PRD from them, using these documents only to add detail.'].join('\n'), files_ingested: 0, prds_generated: 0 } }];
}
const output = [
  '# No requirements provided',
  '',
  'PRD Genie builds a PRD from the requirements you describe **in the chat**.',
  'The documents in Drive are used only to add detail to what you specify —',
  'they are never used on their own.',
  '',
  'Type your requirements (or a request like *"a reporting dashboard that filters by date and exports to PDF"*) to begin.',
].join('\n');
return [{ json: { output, files_ingested: 0, prds_generated: 0 } }];

// Build a Langfuse ingestion batch for ONE file's run.
// This node sits inside the loop, so every reference below resolves to the
// current iteration - not the first file. That distinction matters: reading
// $('Combine All Sources').first() here would tag every trace with file #1.

const asm  = $input.first().json;   // Assemble output + judge scores (via Parse Judge Score)
const cur  = $('Combine All Sources').first().json;                // current batch item
const meta = $('Parse + Validate Extraction').first().json;    // this file's extraction
const cmd  = $('Read Chat Command').first().json;              // chat session

const uid = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, ch => {
  const r = Math.random() * 16 | 0;
  return (ch === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});

const t0 = Date.now();
const iso = (ms = 0) => new Date(t0 + ms).toISOString();
const traceId = uid();
const batch = [];
const push = (type, body) => batch.push({ id: uid(), type, timestamp: iso(), body });

// Estimate only - see langfuse-integration.md before using for cost analysis.
const est = (s) => Math.ceil(String(typeof s === 'string' ? s : JSON.stringify(s ?? '')).length / 4);

const sourceText = String(cur.input_text ?? '');
const sourceFile = asm.source_file ?? cur.source_file ?? asm.test_id ?? 'unknown';

push('trace-create', {
  id: traceId,
  name: (asm.test_id && !['chat','none','unknown','combined'].includes(asm.test_id))
          ? `PRD Genie — ${asm.test_id}` : 'PRD Genie',
  // One sessionId per chat message groups every file of a batch into one session.
  sessionId: cmd.sessionId ?? undefined,
  input: sourceText,
  output: asm.prd_markdown,
  tags: ['drive-ingest', sourceFile, asm.input_assessment,
         asm.halted_at_sufficiency_gate ? 'halted' : 'completed'].filter(Boolean),
  metadata: {
    source_file: sourceFile,
    test_id: asm.test_id,
    stated_count: asm.stated_count,
    ambiguous_count: asm.ambiguous_count,
    contradiction_count: asm.contradiction_count,
    unsupported_items_dropped: asm.unsupported_items_dropped,
    halted_at_sufficiency_gate: asm.halted_at_sufficiency_gate,
    // --- judge audit: makes the completeness/hallucination scores explainable ---
    gt_count: asm.gt_count,
    extracted_count: asm.extracted_count,
    hallucinated_items: asm.hallucinated_items,
    missed_items: asm.missed_items,
    judge_summary: asm.judge_summary,
  },
});

const generation = (name, model, input, output, offset) => {
  push('generation-create', {
    id: uid(), traceId, name, model,
    startTime: iso(offset), endTime: iso(offset + 1000),
    modelParameters: { temperature: 0 },
    input, output,
    usageDetails: { input: est(input), output: est(output), total: est(input) + est(output) },
  });
};

generation('Agent 1 · Requirement Extractor', 'gpt-4o-mini', sourceText, meta.extraction, 0);
if (!asm.halted_at_sufficiency_gate) {
  generation('Agent 2 · PRD Generator', 'gpt-4o', meta.extraction, asm.prd_markdown, 2000);
  generation('Agent 3 · Story Breakdown', 'gpt-4o', asm.prd_markdown, asm.stories_markdown, 4000);
}
generation('Agent 4 · Gap Analyzer', 'gpt-4o-mini', meta.gaps, asm.gap_markdown, 2000);

push('span-create', {
  id: uid(), traceId, name: 'Guardrail · quote validation',
  startTime: iso(1200), endTime: iso(1250),
  level: (asm.unsupported_items_dropped > 0) ? 'WARNING' : 'DEFAULT',
  statusMessage: `${asm.unsupported_items_dropped ?? 0} unsupported item(s) dropped`,
  input: { stated_items_kept: meta.stated_count ?? 0 },
  output: { dropped: meta.dropped_items ?? [] },
});

push('span-create', {
  id: uid(), traceId, name: 'Guardrail · sufficiency gate',
  startTime: iso(1300), endTime: iso(1350),
  level: asm.halted_at_sufficiency_gate ? 'WARNING' : 'DEFAULT',
  statusMessage: asm.halted_at_sufficiency_gate
    ? 'HALTED — no stated requirements; PRD Generator not invoked'
    : `PASSED — ${asm.stated_count} stated requirement(s)`,
  input: { stated_count: asm.stated_count ?? 0 },
  output: { proceeded: !asm.halted_at_sufficiency_gate },
});

// --- evaluation scores, attached to this same trace -------------------------
// 0-1 numerics so Langfuse can filter and chart them. Reported as a PAIR:
// completeness alone rewards loose extraction, hallucination rate alone
// rewards extracting nothing. Only together do they mean anything.
const score = (name, value, comment) => {
  if (value === null || value === undefined || Number.isNaN(Number(value))) return;
  push('score-create', {
    id: uid(), traceId, name,
    value: Number(value), dataType: 'NUMERIC',
    comment: comment || undefined,
  });
};

score('extraction_completeness', asm.completeness, asm.judge_note);   // higher is better
score('hallucination_rate',      asm.hallucination_rate, asm.judge_note); // lower is better
score('format_compliance',       asm.format_compliance,
      (asm.format_failed_checks && asm.format_failed_checks.length)
        ? 'failed: ' + asm.format_failed_checks.join(', ') : 'all 13 checks pass'); // higher is better

return [{ json: { batch } }];

// HTTP node replaced the item with Langfuse's response. Restore the run payload,
// taken from Score Format Compliance so all three eval scores survive.
return [{ json: $('Score Format Compliance').first().json }];

// Parse the judge's verdict and carry it alongside the run payload.
// Failing to parse must never break the run: scores are observability, not output.
const asm = $('Assemble Submission Outputs').first().json;

let j = null;
try {
  let t = $input.first().json;
  t = t.text ?? t.output ?? t.response ?? t;
  if (typeof t === 'string') t = t.replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();
  j = typeof t === 'string' ? JSON.parse(t) : t;
} catch (e) {
  j = null;
}

const clamp01 = (n) => Math.max(0, Math.min(1, Number(n)));

let completeness = null, hallucination_rate = null, judge_note = 'judge unavailable';
if (j && typeof j === 'object') {
  const gtCount = Number(j.ground_truth_count ?? (j.ground_truth || []).length) || 0;
  const points  = Number(j.points_awarded ?? (j.matches || []).reduce((s, m) => s + (Number(m.score) || 0), 0)) || 0;
  completeness = gtCount > 0 ? clamp01(points / gtCount)
                             : clamp01(j.completeness ?? 1);

  // Prefer the judge's own hallucination_rate (scoped: unsupported by primary OR supporting).
  const halls = (j.hallucinations_noted || []).length;
  const extracted = Number(j.extracted_item_count) ||
    ((asm.stated_count || 0) + (asm.ambiguous_count || 0) + (asm.contradiction_count || 0));
  hallucination_rate = (j.hallucination_rate !== undefined && j.hallucination_rate !== null && !Number.isNaN(Number(j.hallucination_rate)))
    ? clamp01(j.hallucination_rate)
    : (extracted > 0 ? clamp01(halls / extracted) : 0);

  judge_note = `${points}/${gtCount} ground truth · ${halls} unsupported item(s)` +
               (j.missed_items?.length ? ` · missed ${j.missed_items.join(', ')}` : '');
}

// Audit trail: expose exactly what the judge flagged so the score is explainable.
  const hallucinated_items = (j && j.hallucinations_noted) ? j.hallucinations_noted : [];
  const missed_items = (j && j.missed_items) ? j.missed_items : [];
  const gt_count = (j && (j.ground_truth_count ?? (j.ground_truth || []).length)) || 0;
  const extracted_count = (j && j.extracted_item_count) || null;
  const judge_summary = (j && j.summary) ? j.summary : '';
  return [{ json: { ...asm, completeness, hallucination_rate, judge_note,
    hallucinated_items, missed_items, gt_count, extracted_count, judge_summary,
    judge_raw: j } }];

// Format compliance (0-1), deterministic. Ported from scripts/score_format_compliance.py
// and verified identical on the same PRDs. Structural only: an abstention is compliant,
// so a "Not discussed in this meeting." section never lowers the score.
const asm = $input.first().json;
const md  = String(asm.prd_markdown || '');

function scoreFormat(md) {
  const ABSTAIN = "Not discussed in this meeting.";
  const SECTIONS = ["Product Overview","Goals and Objectives","User Personas",
    "Feature Requirements","Acceptance Criteria","Out of Scope",
    "Dependencies","Assumptions","Open Questions","Timeline"];
  const headings = Array.from(md.matchAll(/^#{1,3}\s+.*$/gm)).map(m =>
    m[0].replace(/^#+\s*\d*\.?\s*/, "").trim());
  const hl = headings.join(" \n ").toLowerCase();
  const esc = s => s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const hasCols = (section, cols) => {
    const m = md.match(new RegExp(esc(section) + "([\\s\\S]*?)(?=\\n#{1,2}\\s|$)"));
    const body = m ? m[1] : "";
    return body.split("\n").some(line =>
      line.includes("|") && cols.every(c => line.toLowerCase().includes(c.toLowerCase())));
  };
  const ck = {};
  ck.C1  = [3, SECTIONS.filter(s => hl.includes(s.toLowerCase())).length === 10];
  const idx = SECTIONS.filter(s => hl.includes(s.toLowerCase())).map(s => hl.indexOf(s.toLowerCase()));
  ck.C2  = [1, JSON.stringify(idx) === JSON.stringify([...idx].sort((a,b)=>a-b)) && idx.length === 10];
  ck.C3  = [1, hl.includes("functional") && hl.includes("non-functional")];
  ck.C4  = [1, hasCols("Feature Requirements", ["Requirement","Priority","Source"])];
  ck.C5  = [1, hasCols("Feature Requirements", ["Requirement","Category","Target"])];
  ck.C6  = [1, hasCols("Dependencies", ["Owner","Status","Risk"])];
  ck.C7  = [1, hasCols("Timeline", ["Milestone","Target"]) || md.includes(ABSTAIN)];
  ck.C8  = [1, /\bFR-\d+\b/.test(md) || md.includes(ABSTAIN)];
  ck.C9  = [1, !/Priority[:|]\s*(High|Low|Critical|P\d)/i.test(md)];
  const frRows = md.split("\n").filter(l => /\bFR-\d+\b/.test(l));
  ck.C10 = [1, frRows.length ? frRows.every(r => r.split("|").filter(x=>x.trim()).length >= 4) : true];
  ck.C11 = [1, !/\[\s*\]|<[^>]*>|FR-001\s*\|\s*\|/.test(md)];
  ck.C12 = [1, !hl.includes("not discussed")];
  const ALLOWED = SECTIONS.map(s=>s.toLowerCase()).concat(["functional","product requirements document"]);
  ck.C13 = [1, headings.every(x => { const xl=x.toLowerCase();
    return ALLOWED.some(a => xl.includes(a)) || x.length < 3; })];

  let earned=0, total=0; const failed=[];
  for (const [k,[wgt,ok]] of Object.entries(ck)) { total+=wgt; if(ok) earned+=wgt; else failed.push(k); }
  return { score: Math.round(earned/total*1000)/1000, points: earned, max: total, failed };
}

// An empty/halted run has no PRD to grade: report null rather than a misleading 0 or 1.
const fc = asm.halted_at_sufficiency_gate ? { score: null, failed: [] } : scoreFormat(md);

return [{ json: { ...asm,
  format_compliance: fc.score,
  format_failed_checks: fc.failed } }];

// Collapse the two mutually-exclusive branches (generated vs halted) into one
// item. Only one upstream branch fires per run, so this executes exactly once.
return [{ json: $input.first().json }];
